func:
const p = msg.topic.split('/');
if (p.length < 5) return null;
const serial_number = p[3];
const d = msg.payload || {};

const infoMap = global.get('info_map') || {};
infoMap[serial_number] = {
    type:            d.device_type || '',
    production_date: d.production_date || '',
    hw_version:      d.hw_version || 0,
    serial_number:   d.serial_number || serial_number,
};
global.set('info_map', infoMap);

// Forward so the control tab device list refreshes
msg.payload = serial_number;
return msg;

const BAT_MAP={BATTERY_TYPE_UNKNOWN:0,BATTERY_AGM:1,BATTERY_LIQUID:2,BATTERY_LFP:3,BATTERY_LFP_HIGH_TEMP:4,BATTERY_LFP_MEDIUM_TEMP:5,BATTERY_LFP_LOW_TEMP:6};
const LVD_MAP={LVD_MODE_SOC:0,LVD_MODE_VOLTAGE:1};
const NIGHT_MAP={NIGHT_MODE_ALWAYS_ON:0,NIGHT_MODE_D2D:1,NIGHT_MODE_DD:2,NIGHT_MODE_MN:3};
function normEnum(v,map){if(v===null||v===undefined)return 0;if(typeof v==='object'&&'value'in v)v=v.value;if(typeof v==='string'&&map[v]!==undefined)return map[v];return parseInt(v)||0;}

const p = msg.topic.split('/');
const serial_number = p[3];
const d = msg.payload || {};
const settingsMap = global.get('settings_cache') || {};

settingsMap[serial_number] = {
    battery_type:               normEnum(d.battery_type, BAT_MAP),
    capacity_ah:                d.capacity_ah             || 100,
    lvd_voltage_mv:             d.lvd_voltage_mv           || 11000,
    lvd_mode:                   normEnum(d.lvd_mode, LVD_MAP),
    night_mode:                 normEnum(d.night_mode, NIGHT_MAP),
    evening_minutes:            d.evening_minutes          || 0,
    morning_minutes:            d.morning_minutes          || 0,
    night_threshold_mv:         d.night_threshold_mv       || 11500,
    dimming_mode:               normEnum(d.dimming_mode, NIGHT_MAP),
    evening_minutes_dimming:    d.evening_minutes_dimming  || 0,
    morning_minutes_dimming:    d.morning_minutes_dimming  || 0,
    dimming_pct:                d.dimming_pct              || 100,
    base_dimming_pct:           d.base_dimming_pct         || 30,
    dali_power_enable:          !!(d.advanced_flags & 1),
    alc_dimming_enable:         !!(d.advanced_flags & 2),
    advanced_flags:             d.advanced_flags           || 0
};
global.set('settings_cache', settingsMap);

// Re-populate control panel if this device is currently selected
const selected = global.get('selected_serial');
return (selected === serial_number) ? [{ payload: serial_number }] : [null];

const p = msg.topic.split('/');
const serial_number = p[3];
const zone = p[1];
const isOnline = msg.payload.toString().trim() === '1';
const key = 'online_' + serial_number;
const wasOnline = context.get(key);
context.set(key, isOnline);

const onlineMap = global.get('online_map') || {};
onlineMap[serial_number] = { online: isOnline, ts: new Date().toISOString() };
global.set('online_map', onlineMap);

if (!isOnline && wasOnline !== false) {
    const ts = new Date().toISOString();
    return [{ payload: {
        severity: 'critical', condition: 'Device offline',
        emailNeeded: true, serial_number, zone, ts,
        subject: '[MPPT CRITICAL] ' + serial_number + ' offline',
        body: 'Device ' + serial_number + ' (zone: ' + zone + ') went offline at ' + ts
    }}];
}
if (isOnline && wasOnline === false) {
    node.log(serial_number + ' back online');
}
return null;

if (!msg.payload || !msg.payload.subject) return null;
msg.topic = msg.payload.subject;
msg.payload = msg.payload.body;
return msg;

const p = msg.topic.split('/');
if (p.length < 5) return [null, null, null];
const zone  = p[1];
const gw    = p[2];
const serial_number= p[3];
const d     = msg.payload || {};

// Pull hw_version from info cache as fallback
const info  = (global.get('info_map') || {})[serial_number] || {};
const hwVer = String(d.hw_version || info.hw_version || 0);

// Fault mask -> individual boolean fields for InfluxDB
const fm = d.fault_mask || 0;
const faults = {
    battery_over_voltage:   (fm & 0x01) ? 1 : 0,
    pv_over_voltage:        (fm & 0x02) ? 1 : 0,
    controller_over_temp:   (fm & 0x04) ? 1 : 0,
    charge_over_current:    (fm & 0x08) ? 1 : 0,
    lvd_active:             (fm & 0x10) ? 1 : 0,
    over_discharge_current: (fm & 0x20) ? 1 : 0,
    battery_over_temp:      (fm & 0x40) ? 1 : 0,
    battery_under_temp:     (fm & 0x80) ? 1 : 0,
};

//  Update fleet state (used by overview dashboard)
const fleet = global.get('fleet') || {};
fleet[serial_number] = {
    serial_number, zone, gateway_id: gw, hw_version: hwVer,
    bat: {
        battery_voltage_mv:      d.battery_voltage_mv      || 0,
        battery_soc_pct:         d.battery_soc_pct         || 0,
        charge_current_ma:     d.charge_current_ma10 * 10|| 0,
        charge_power_w:          d.charge_power_w          || 0,
        end_of_charge_voltage_mv:d.end_of_charge_voltage_mv|| 0,
        charge_mode:             d.charge_mode             || 'unknown',
        is_night:                !!( d.flags & (1 << 1) ),
        bat_op_days:             d.bat_op_days             || 0,
        energy_in_daily_wh:      d.energy_in_daily_wh      || 0,
        energy_out_daily_wh:     d.energy_out_daily_wh     || 0,
        energy_retained_wh:      d.energy_retained_wh      || 0,
        detected:                !!( d.flags & (1 << 0) ),
        charge_state_mask:       d.charge_state_mask       || 0,
    },
    load: {
        load_on:         !!( d.flags & (1 << 2) ),
        night_mode:      !!( d.flags & (1 << 3) ),
        lvd_active:      !!( d.flags & (1 << 4) ),
        user_disconnect: !!( d.flags & (1 << 5) ),
        over_current:    !!( d.flags & (1 << 6) ),
        load_current_ma:  d.load_current_ma10 * 10|| 0,
        load_power_w:       d.load_power_w        || 0,
        state_mask:         d.load_state_mask     || 0,
    },
    pv: {
        pv_voltage_mv:        d.pv_voltage_mv        || 0,
        pv_target_voltage_mv: d.pv_target_voltage_mv || 0,
        detected:             !!( d.flags & (1 << 7) ),
    },
    faults,
    ts: Math.floor(Date.now() / 1000),
};
global.set('fleet', fleet);

const dev = fleet[serial_number];
const tags = { zone, gateway_id: gw, serial_number, hw_version: hwVer,
               charge_mode: d.charge_mode || 'unknown' };

// Output 1: influxdb telemetry fields
const telFields = {
    battery_voltage_mv:   d.battery_voltage_mv   || 0,
    soc_pct:              d.battery_soc_pct      || 0,
    charge_current_ma:  d.charge_current_ma10 * 10 || 0,
    charge_power_w:       d.charge_power_w       || 0,
    is_night:             dev.bat.is_night        ? 1 : 0,
    energy_in_daily_wh:   d.energy_in_daily_wh   || 0,
    energy_out_daily_wh:  d.energy_out_daily_wh  || 0,
    energy_retained_wh:   d.energy_retained_wh   || 0,
    load_on:              dev.load.load_on        ? 1 : 0,
    lvd_active:           (dev.load.lvd_active || faults.lvd_active) ? 1 : 0,
    load_current_ma:    d.load_current_ma10 * 10    || 0,
    load_power_w:         d.load_power_w          || 0,
    pv_voltage_mv:        d.pv_voltage_mv         || 0,
    pv_target_voltage_mv: d.pv_target_voltage_mv  || 0,
    internal_temp_c:      d.internal_temp_c       || 0,
    external_temp_c:      d.external_temp_c       || 0,
    led_voltage_mv:       d.led_voltage_mv        || 0,
    led_current_ma:     d.led_current_ma10 * 10   || 0,
    led_power_w:          d.led_power_w           || 0,
    load_state_mask:      d.load_state_mask       || 0,
    charge_state_mask:    d.charge_state_mask     || 0,
    flags:                d.flags                 || 0,
};

// Output 0: alert msg
const alertMsg = {
    serial_number, zone,
    soc_pct:   d.battery_soc_pct || 0,
    faults,
    lvd_active: dev.load.lvd_active,
    ts: new Date().toISOString(),
};

return [
    { payload: alertMsg },
    { payload: [telFields, tags] },
    { payload: [faults,   tags] },
];

const { serial, zone, soc_pct, faults, lvd_active, ts } = msg.payload;

const checks = [
    { key: 'low_soc', cond: soc_pct > 0 && soc_pct < 10, label: 'Battery SOC critical (' + soc_pct + '%)' },
    { key: 'lvd', cond: !!(faults.lvd_active || lvd_active), label: 'LVD active' },
    { key: 'bov', cond: !!faults.battery_over_voltage, label: 'Battery over voltage' },
    { key: 'odc', cond: !!faults.over_discharge_current, label: 'Over discharge current' },
    { key: 'bat_hot', cond: !!faults.battery_over_temp, label: 'Battery over temperature' },
    { key: 'bat_cold', cond: !!faults.battery_under_temp, label: 'Battery under temperature' },
];

const COOLDOWN_MS = 3600000; // 1 hour per condition per device
const now = Date.now();
const out = [];

for (const c of checks) {
    if (!c.cond) continue;

    const stateKey = 'alert_' + serial + '_' + c.key;
    const lastSent = context.get(stateKey) || 0;

    if (now - lastSent < COOLDOWN_MS) continue;

    context.set(stateKey, now);

    out.push({
        payload: {
            subject: '[MPPT CRITICAL] ' + serial + ' - ' + c.label,
            body:
                'Device: ' + serial + '\n' +
                'Zone: ' + zone + '\n' +
                'Condition: ' + c.label + '\n' +
                'Timestamp: ' + ts,
        }
    });
}

return out.length ? out : null;

const p = msg.topic.split('/');
if (p.length < 6) return [null, null, null];
const [, zone, gateway, serial_number,, sub] = p;

const dl  = msg.payload;
const info = (global.get('info_map') || {})[serial_number] || {};
const ct  = { serial_number, gateway_id: gateway, zone, hw_version: String(info.hw_version || 0) };

function unpackStateFlags(sf) {
    return {
        load_disconnect:  (sf >> 0) & 1,
        full_charge:      (sf >> 1) & 1,
        pv_over_current:  (sf >> 2) & 1,
        load_over_current:(sf >> 3) & 1,
        bat_over_voltage: (sf >> 4) & 1,
        low_soc:          (sf >> 5) & 1,
        temp_pv_over:     (sf >> 6) & 1,
        temp_pv_low:      (sf >> 7) & 1,
        temp_load_over:   (sf >> 8) & 1,
    };
}

function scaleEntry(e, indexKey, ahMul, socScale) {
    return {
        [indexKey]:      e.index          || 0,
        vbat_min_mv:     (e.vbat_min_mv   || 0) * 100,
        vbat_max_mv:     (e.vbat_max_mv   || 0) * 100,
        vpv_min_mv:      (e.vpv_min_mv    || 0) * 500,
        vpv_max_mv:      (e.vpv_max_mv    || 0) * 500,
        ah_charge_mah:   (e.ah_charge_mah || 0) * ahMul,
        ah_load_mah:     (e.ah_load_mah   || 0) * ahMul,
        il_max_ma:       (e.il_max_ma     || 0) * 500,
        ipv_max_ma:      (e.ipv_max_ma    || 0) * 500,
        soc_pct:         (e.soc_pct       || 0) * socScale,
        ext_temp_max_c:  e.ext_temp_max_c || 0,
        ext_temp_min_c:  e.ext_temp_min_c || 0,
        nightlength_min: (e.nightlength_min|| 0) * 10,
        ...unpackStateFlags(e.state_flags  || 0),
    };
}

if (sub === 'summary') {
    return [{ payload: [{
        recorded_days:              dl.recorded_days              || 0,
        days_with_lvd:              dl.days_with_lvd              || 0,
        months_without_full_charge: dl.months_without_full_charge || 0,
        avg_morning_soc_pct:        (dl.recorded_days > 0) ? dl.avg_morning_soc_pct * 6.6 / dl.recorded_days : 0 || 0,
        total_ah_charge_mah:        dl.total_ah_charge_mah / 10   || 0,
        total_ah_load_mah:          dl.total_ah_load_mah / 10     || 0,
    }, ct] }, null, null];
}

if (sub === 'daily') {
    const msgs = (dl.daily_logs || []).map(e => ({
        payload: [scaleEntry(e, 'day_num', 100, 6.6),
                  { ...ct, day_index: String(e.index) }],
    }));
    return [null, msgs.length ? msgs : null, null];
}

if (sub === 'monthly') {
    const msgs = (dl.monthly_logs || []).map(e => ({
        payload: [scaleEntry(e, 'month_num', 1000, 1.0),
                  { ...ct, month_index: String(e.index) }],
    }));
    return [null, null, msgs.length ? msgs : null];
}

return [null, null, null];

const BAT_MAP={BATTERY_TYPE_UNKNOWN:0,BATTERY_AGM:1,BATTERY_LIQUID:2,BATTERY_LFP:3,BATTERY_LFP_HIGH_TEMP:4,BATTERY_LFP_MEDIUM_TEMP:5,BATTERY_LFP_LOW_TEMP:6};
const LVD_MAP={LVD_MODE_SOC:0,LVD_MODE_VOLTAGE:1};
const NIGHT_MAP={NIGHT_MODE_ALWAYS_ON:0,NIGHT_MODE_D2D:1,NIGHT_MODE_DD:2,NIGHT_MODE_MN:3};
function normEnum(v,map){if(v===null||v===undefined)return 0;if(typeof v==='object'&&'value'in v)v=v.value;if(typeof v==='string'&&map[v]!==undefined)return map[v];return parseInt(v)||0;}

const serial_number = msg.payload;
const out = new Array(18).fill(null);

if (!serial_number || typeof serial_number !== 'string') {
    global.set('selected_serial', null);
    global.set('device_baseline', null);
    out[0] = { payload: '<div style="padding:60px 20px;text-align:center;color:#64748b;">Select a device from the dropdown above</div>' };
    node.send(out);
    return null;
}

global.set('selected_serial', serial_number);

const settingsMap = global.get('settings_cache') || {};
const s = settingsMap[serial_number] || null;

// Snapshot normalized baseline - this is what we compare against on Send
flow.set('device_baseline', s ? JSON.parse(JSON.stringify(s)) : null);

const fleet     = global.get('fleet')      || {};
const infoMap   = global.get('info_map')   || {};
const onlineMap = global.get('online_map') || {};
const dev    = fleet[serial_number]    || {};
const info   = infoMap[serial_number]  || {};
const online = !onlineMap[serial_number] || onlineMap[serial_number].online !== false;
const sc     = online ? '#22c55e' : '#ef4444';

out[0] = { payload:
    '<div style="background:#1e2937;padding:18px;border-radius:8px;margin-bottom:16px;">' +
    '<div style="display:flex;align-items:center;gap:12px;margin-bottom:14px;">' +
    '<div style="width:16px;height:16px;border-radius:50%;background:' + sc + ';"></div>' +
    '<span style="font-size:26px;font-weight:700;">' + serial_number + '</span>' +
    '<span style="color:' + sc + ';font-weight:700;">' + (online ? '● ONLINE' : '○ OFFLINE') + '</span></div>' +
    '<div style="display:grid;grid-template-columns:120px 1fr;gap:8px;font-size:14.5px;line-height:1.6;">' +
    '<div style="color:#64748b;">Model</div><div style="color:#e2e8f0;">' + (info.type||'MPPT') + ' V' + (info.hw_version||'?') + '</div>' +
    '<div style="color:#64748b;">Zone</div><div style="color:#e2e8f0;">' + (dev.zone||'default') + '</div>' +
    '</div></div>'
};

const BL = ['Unknown','AGM/Gel','Liquid','LiFePO4','LiFePO4 - High Temp','LiFePO4 - Medium Temp','LiFePO4 - Low Temp'];
const NL = ['Off','Dusk to Dawn (D2D)','Dusk and Dawn (DD)','Middle of the Night (MN)'];

out[17] = { payload: s ?
    '<div style="background:#1e2937;padding:18px;border-radius:8px;">' +
    '<div style="font-size:15px;font-weight:700;color:#e2e8f0;margin-bottom:16px;">DEVICE CONFIGURATION</div>' +
    '<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px 30px;font-size:14.5px;">' +
    '<div><span style="color:#64748b;">Battery Type</span><br><strong>' + (BL[s.battery_type]||s.battery_type) + '</strong></div>' +
    '<div><span style="color:#64748b;">Capacity</span><br><strong>' + s.capacity_ah + '</strong> Ah</div>' +
    '<div><span style="color:#64748b;">LVD</span><br><strong>' + (s.lvd_voltage_mv/1000).toFixed(1) + ' V</strong></div>' +
    '<div><span style="color:#64748b;">LVD Mode</span><br><strong>' + (s.lvd_mode===1?'Voltage':'SOC') + '</strong></div>' +
    '<div><span style="color:#64748b;">Night Mode</span><br><strong>' + (NL[s.night_mode]||s.night_mode) + '</strong></div>' +
    '<div><span style="color:#64748b;">Dim Mode</span><br><strong>' + (NL[s.dimming_mode]||s.dimming_mode) + '</strong></div>' +
    '<div><span style="color:#64748b;">DALI</span><br><strong>' + (s.dali_power_enable?'On':'Off') + '</strong></div>' +
    '<div><span style="color:#64748b;">ALC</span><br><strong>' + (s.alc_dimming_enable?'On':'Off') + '</strong></div>' +
    '</div></div>'
    : '<div style="background:#1e2937;padding:40px;text-align:center;color:#64748b;border-radius:8px;">No settings cached</div>'
};

if (s) {
    // Dropdowns: String values matching option values in widget definition
    // Number inputs: raw numbers; Switches: booleans
    out[1]  = { payload: String(s.battery_type) };   // w-bat-type
    out[2]  = { payload: s.capacity_ah };             // w-cap-ah
    out[3]  = { payload: s.lvd_voltage_mv };          // w-lvd-v
    out[4]  = { payload: s.lvd_mode === 1 };          // w-lvd-mode switch
    out[5]  = { payload: String(s.night_mode) };      // w-night-mode
    out[6]  = { payload: s.evening_minutes };
    out[7]  = { payload: s.morning_minutes };
    out[8]  = { payload: s.night_threshold_mv };
    out[9]  = { payload: String(s.dimming_mode) };    // w-dim-mode
    out[10] = { payload: s.evening_minutes_dimming };
    out[11] = { payload: s.morning_minutes_dimming };
    out[12] = { payload: s.dimming_pct };
    out[13] = { payload: s.base_dimming_pct };
    out[14] = { payload: s.dali_power_enable };       // w-dali switch
    out[15] = { payload: s.alc_dimming_enable };      // w-alc switch
}

node.send(out);
return null;

if (msg.topic === 'send')   return [msg, null];
if (msg.topic === 'reload') return [null, msg];
return null;

const serial_number = global.get('selected_serial');
if (!serial_number) return null;
msg.payload = serial_number;
return msg;

const serial_number = global.get('selected_serial');
if (!serial_number) return null;

const fleet = global.get('fleet') || {};
const dev   = fleet[serial_number]        || {};
const zone  = dev.zone             || 'default';
const gw    = dev.gateway_id       || 'unknown';

const baseline = flow.get('device_baseline');
if (!baseline) { node.warn('No baseline for ' + serial_number); return null; }

const g      = (t) => flow.get('w_w-' + t);
const toInt  = (v) => { const n = parseInt(v); return isNaN(n) ? undefined : n; };
const toBool = (v) => v === true || v === 'true';

const current = {
    battery_type:            toInt(g('bat-type')),
    capacity_ah:             toInt(g('cap-ah')),
    lvd_voltage_mv:          toInt(g('lvd-v')),
    lvd_mode:                toBool(g('lvd-mode')) ? 1 : 0,
    night_mode:              toInt(g('night-mode')),
    evening_minutes:         toInt(g('eve-min')),
    morning_minutes:         toInt(g('morn-min')),
    night_threshold_mv:      toInt(g('night-thresh')),
    dimming_mode:            toInt(g('dim-mode')),
    evening_minutes_dimming: toInt(g('dim-eve-min')),
    morning_minutes_dimming: toInt(g('dim-morn-min')),
    dimming_pct:             toInt(g('dim-pct')),
    base_dimming_pct:        toInt(g('base-dim-pct')),
};

const setSettings = {};
let changeCount = 0;

for (const [key, val] of Object.entries(current)) {
    if (val !== undefined && val !== baseline[key]) {
        setSettings[key] = val;
        changeCount++;
    }
}

const curDali = toBool(g('dali'));
const curAlc  = toBool(g('alc'));
if (curDali !== !!baseline.dali_power_enable || curAlc !== !!baseline.alc_dimming_enable) {
    setSettings.advanced_flags = (curDali ? 1 : 0) | (curAlc ? 2 : 0);
    changeCount++;
}

if (changeCount === 0) { node.warn('No changes vs baseline for ' + serial_number); return null; }

const requestId = serial_number + '_' + Date.now();
msg.topic   = 'mppt/' + zone + '/' + gw + '/' + serial_number + '/cmd';
msg.payload = { request_id: requestId, timestamp: Math.floor(Date.now()/1000), set_settings: setSettings };

const ts    = new Date().toLocaleTimeString();
const entry = '<div style="font-size:12px;padding:4px 0;border-bottom:1px solid #334155">' +
    '<span style="color:#64748b">' + ts + '</span> ' +
    '<span style="color:#3b82f6;font-weight:600">SEND</span> ' +
    serial_number + ' - ' + requestId +
    ' <span style="color:#eab308">(' + changeCount + ' changed)</span></div>';
flow.set('cmd_log', entry + (flow.get('cmd_log') || ''));
return msg;

var log = flow.get('cmd_log') || '<span style="color:#64748b;font-style:italic">No commands sent yet.</span>';

msg.payload =
'<div style="width:100%;min-width:100%;font-family:monospace;font-size:14px;line-height:1.4;padding:10px;box-sizing:border-box;border:1px solid #e5e7eb;border-radius:6px;background:#fff;">'
+ log +
'</div>';

return msg;

const p      = msg.topic.split('/');
const serial_number = p.length >= 4 ? p[3] : '?';
const ts     = new Date().toLocaleTimeString();
const pl     = msg.payload || {};

const ok     = pl.ok;
const reason = pl.reason || '';
const reqId  = pl.request_id || '';

const color = ok ? '#4ade80' : '#f87171';
const label = ok ? 'ACK ✓'  : 'ACK ✗';
const idStr = reqId ? ` <span style="color:#475569">[${reqId.split('_').pop()}]</span>` : '';

const entry =
    `<div style="font-size:12px;padding:4px 0;border-bottom:1px solid #1e293b">` +
    `<span style="color:#475569">${ts}</span> ` +
    `<span style="color:${color};font-weight:700">${label}</span> ` +
    `<span style="color:#94a3b8">${serial_number}</span>${idStr}` +
    `${reason ? '<span style="color:#64748b"> - ' + reason + '</span>' : ''}` +
    `</div>`;

const log = flow.get('cmd_log') || '';
flow.set('cmd_log', entry + log);

msg.payload =
    `<div style="font-family:monospace;max-height:260px;overflow-y:auto;font-size:12px">` +
    flow.get('cmd_log') + '</div>';
return msg;

var fleet = global.get('fleet') || {};

var opts = Object.keys(fleet)
    .sort()
    .map(function(s) {
        var dev = fleet[s] || {};
        var zone = dev.zone || 'default';
        var onlineMap = global.get('online_map') || {};
        var isOnline = onlineMap[s] ? onlineMap[s].online !== false : true;
        var icon = isOnline ? ' ●' : ' ○';
        return {
            value: s,
            label: s + ' [' + zone + ']' + icon
        };
    });

